import React, { useMemo } from 'react';
import PropTypes from 'prop-types';
import { useIntl } from 'gatsby-plugin-intl';
import { graphql } from 'gatsby';
import { makeStyles } from '@material-ui/core/styles';
import { Typography } from '@material-ui/core';

// Utils
import { getAlternateLangLinks } from '../utils/gatsby-frontend-helpers';

// Components
import Link from '../components/Link';
import Layout from '../components/Layout';
import SEO from '../components/SEO';
import PostsList from '../components/PostsList';

const useStyles = makeStyles((theme) => ({
    blogPostsText: {
        margin: '15px 0',
    },
    postsListWrapper: {
        marginBottom: '10px',
        padding: '0 5px',
    },
    archiveText: {
        padding: '10px 0',
    },
}));

const Blog = ({ location, data, pageContext }) => {
    const posts = data.allMarkdownRemark.edges;
    const intl = useIntl();
    const classes = useStyles();
    const alternateLangLinks = useMemo(
        () => getAlternateLangLinks(pageContext, data.site.siteMetadata.siteUrl),
        [data.site.siteMetadata.siteUrl, pageContext]
    );

    return (
        <Layout>
            <SEO
                lang={intl.locale}
                pathname={location?.pathname}
                title={intl.formatMessage({ id: 'blog' })}
                keywords={[
                    intl.formatMessage({ id: 'seo_keywords.personal_blog' }),
                    intl.formatMessage({ id: 'seo_keywords.tips' }),
                    intl.formatMessage({ id: 'seo_keywords.travels' }),
                    intl.formatMessage({ id: 'seo_keywords.lifehacks' }),
                    intl.formatMessage({ id: 'seo_keywords.games' }),
                    intl.formatMessage({ id: 'seo_keywords.development' }),
                    intl.formatMessage({ id: 'seo_keywords.reviews' }),
                ]}
                alternateLangLinks={alternateLangLinks}
            />
            <Typography
                className={classes.blogPostsText}
                color="textPrimary"
                variant="h4"
            >
                {intl.formatMessage({ id: 'blog_posts' })}
            </Typography>
            <PostsList
                className={classes.postsListWrapper}
                posts={posts}
                locale={intl.locale}
                quantity={10}
            />
            <Link to="/archive">
                <Typography
                    color="textPrimary"
                    variant="overline"
                >
                    {intl.formatMessage({ id: 'archive' })}
                </Typography>
            </Link>
        </Layout>
    );
};

Blog.propTypes = {
    data: PropTypes.shape({
        allMarkdownRemark: PropTypes.shape({
            edges: PropTypes.arrayOf(PropTypes.object.isRequired).isRequired,
        }).isRequired,
        site: PropTypes.shape({
            siteMetadata: PropTypes.shape({
                siteUrl: PropTypes.string.isRequired,
            }).isRequired,
        }).isRequired,
    }).isRequired,
};

export default Blog;

export const pageQuery = graphql`
    query Blog($locale: String) {
        site {
            siteMetadata {
                siteUrl
            }
        }
        allMarkdownRemark(
            filter: {
                fields: { locale: { eq: $locale } }
                frontmatter: { show: { eq: true } }
            }
            sort: { fields: [frontmatter___date], order: DESC }
        ) {
            edges {
                node {
                    excerpt(pruneLength: 60)
                    fields {
                        slug
                        path
                        locale
                        readingTime {
                            minutes
                        }
                    }
                    frontmatter {
                        date
                        title
                        hideExcerpt
                    }
                }
            }
        }
    }
`;
